// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract TouristSafety {
    struct Tourist {
        string name;
        string identityHash;
        bool isRegistered;
    }

    struct Incident {
        address reporter;
        string location;
        string details;
        uint256 timestamp;
        bool verified;
    }

    mapping(address => Tourist) public tourists;
    Incident[] public incidents;
    address public admin;

    event TouristRegistered(address indexed touristAddress, string name);
    event IncidentReported(uint256 indexed incidentId, address indexed reporter, string location);
    event IncidentVerified(uint256 indexed incidentId, bool verified);

    constructor() {
        admin = msg.sender;
    }

    function registerTourist(string memory _name, string memory _identityHash) public {
        require(!tourists[msg.sender].isRegistered, "Already registered");
        tourists[msg.sender] = Tourist(_name, _identityHash, true);
        emit TouristRegistered(msg.sender, _name);
    }

    function reportIncident(string memory _location, string memory _details) public {
        incidents.push(Incident(msg.sender, _location, _details, block.timestamp, false));
        emit IncidentReported(incidents.length - 1, msg.sender, _location);
    }

    function verifyIncident(uint256 _incidentId) public {
        require(msg.sender == admin, "Only admin can verify");
        require(_incidentId < incidents.length, "Invalid incident ID");
        incidents[_incidentId].verified = true;
        emit IncidentVerified(_incidentId, true);
    }

    function getIncidentCount() public view returns (uint256) {
        return incidents.length;
    }
}
